#ifndef amb_temp
#define amb_temp 80.0f
#endif

__kernel void hotspot(
    int iter,
    __global const float *power,
    __global const float *temp_in,
    __global float *temp_out,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;
    float Cap_1 = step / Cap;

    int c_start = get_group_id(0) * BLOCK_SIZE;
    int r_start = get_group_id(1) * BLOCK_SIZE;
    int local_c = get_local_id(0);
    int local_r = get_local_id(1);
    int c = c_start + local_c;
    int r = r_start + local_r;

    if (r >= row || c >= col) return;

    // Local memory for this block's temperatures
    __local float local_temp[BLOCK_SIZE][BLOCK_SIZE];

    // Initialize with input temperatures
    local_temp[local_r][local_c] = temp_in[r * col + c];
    barrier(CLK_LOCAL_MEM_FENCE);

    float current_temp = local_temp[local_r][local_c];
    int idx = r * col + c;

    for (int i = 0; i < iter; i++) {
        float delta;

        // Get neighbor temperatures
        float temp_up, temp_down, temp_left, temp_right;

        // Up neighbor (r-1)
        if (r == 0) {
            temp_up = amb_temp;
        } else if (local_r == 0) {
            temp_up = temp_in[(r - 1) * col + c];
        } else {
            temp_up = local_temp[local_r - 1][local_c];
        }

        // Down neighbor (r+1)
        if (r == row - 1) {
            temp_down = amb_temp;
        } else if (local_r == BLOCK_SIZE - 1) {
            temp_down = temp_in[(r + 1) * col + c];
        } else {
            temp_down = local_temp[local_r + 1][local_c];
        }

        // Left neighbor (c-1)
        if (c == 0) {
            temp_left = amb_temp;
        } else if (local_c == 0) {
            temp_left = temp_in[r * col + c - 1];
        } else {
            temp_left = local_temp[local_r][local_c - 1];
        }

        // Right neighbor (c+1)
        if (c == col - 1) {
            temp_right = amb_temp;
        } else if (local_c == BLOCK_SIZE - 1) {
            temp_right = temp_in[r * col + c + 1];
        } else {
            temp_right = local_temp[local_r][local_c + 1];
        }

        // Compute based on boundary conditions
        if (r == 0 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_right - current_temp) * Rx_1 +
                (temp_down - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == 0 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_left - current_temp) * Rx_1 +
                (temp_down - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == row - 1 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_left - current_temp) * Rx_1 +
                (temp_up - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == row - 1 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_right - current_temp) * Rx_1 +
                (temp_up - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_right + temp_left - 2.0f * current_temp) * Rx_1 +
                (temp_down - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_down + temp_up - 2.0f * current_temp) * Ry_1 +
                (temp_left - current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == row - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_right + temp_left - 2.0f * current_temp) * Rx_1 +
                (temp_up - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_down + temp_up - 2.0f * current_temp) * Ry_1 +
                (temp_right - current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else {
            delta = Cap_1 * (power[idx] +
                (temp_down + temp_up - 2.0f * current_temp) * Ry_1 +
                (temp_right + temp_left - 2.0f * current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        }

        current_temp = current_temp + delta;
        local_temp[local_r][local_c] = current_temp;
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    temp_out[r * col + c] = current_temp;
}
